SELECT 
FROM sys_notice_info
WHERE delete_flag = 0

    AND title LIKE CONCAT('%', #{title}, '%')


    AND notice_type = #{noticeType}


    AND level = #{level}


    AND status = #{status}

ORDER BY create_time DESC

